package com.agent.drift.api.impl;  import com.agent.drift.enums.DriftLevel; import com.agent.drift.model.DriftCorrectAction; import org.junit.jupiter.api.DisplayName; import org.junit.jupiter.api.Test;  import static org.assertj.core.api.Assertions.assertThat;  /**  * {@link DriftCorrectorImpl} 单元测试。  */ class DriftCorrectorImplTest {      private final DriftCorrectorImpl corrector = new DriftCorrectorImpl();      @Test     @DisplayName("会话级纠正: 注入核心约束摘要, 返回 true")     void shouldApplySessionCorrection() {         DriftCorrectAction action = new DriftCorrectAction(DriftLevel.SESSION, "a1");         action.setCoreConstraintSummary("必须引用来源标签");          assertThat(corrector.correct(action)).isTrue();         assertThat(corrector.getSessionInjection("a1")).isEqualTo("必须引用来源标签");     }      @Test     @DisplayName("系统级纠正: 回滚至目标版本, 返回 true")     void shouldApplySystemRollback() {         DriftCorrectAction action = new DriftCorrectAction(DriftLevel.SYSTEM, "a1");         action.setTargetVersion("v1.2.0");          assertThat(corrector.correct(action)).isTrue();         assertThat(corrector.getSystemRollbackTarget("a1")).isEqualTo("v1.2.0");     }      @Test     @DisplayName("空 action / 缺少 level / 缺少 agentId: 返回 false")     void shouldRejectInvalidAction() {         assertThat(corrector.correct(null)).isFalse();          DriftCorrectAction noLevel = new DriftCorrectAction();         noLevel.setAgentId("a1");         assertThat(corrector.correct(noLevel)).isFalse();          DriftCorrectAction noAgent = new DriftCorrectAction();         noAgent.setLevel(DriftLevel.SESSION);         assertThat(corrector.correct(noAgent)).isFalse();     } }